from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist (or related entities) into a single,
    fluent English sentence. Handles a variety of predicates and joins multiple
    facts with commas and a final conjunction.
    """
    if not triples:
        return ""

    # Identify the main subject (artist) - typically appears most frequently
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Build fragments for each triple
    fragments = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Generate natural language for each predicate type
        if p == "birthDate":
            fragment = f"{s} was born on {o}"
        elif p == "deathDate":
            fragment = f"{s} died on {o}"
        elif p == "birthPlace":
            fragment = f"{s} was born in {o}"
        elif p == "deathPlace":
            fragment = f"{s} died in {o}"
        elif p == "origin":
            fragment = f"{s} originates from {o}"
        elif p == "nationality":
            fragment = f"{s} is {o}"
        elif p == "genre":
            fragment = f"{s} performs {o}"
        elif p == "instrument":
            fragment = f"{s} plays the {o}"
        elif p == "occupation":
            fragment = f"{s} works as a {o}"
        elif p == "associatedBand/associatedMusicalArtist":
            fragment = f"{s} is associated with {o}"
        elif p == "recordLabel":
            fragment = f"{s} is signed to {o}"
        elif p == "activeYearsStartYear":
            fragment = f"{s} started their career in {o}"
        elif p == "activeYearsEndYear":
            fragment = f"{s} ended their career in {o}"
        elif p == "birthYear":
            fragment = f"{s} was born in {o}"
        elif p == "capital":
            fragment = f"The capital of {s} is {o}"
        elif p == "country":
            fragment = f"{s} is located in {o}"
        elif p in {"language", "officialLanguage"}:
            fragment = f"The language of {s} is {o}"
        elif p == "parentCompany":
            fragment = f"{s} is owned by {o}"
        elif p == "bandMember":
            fragment = f"{s} includes member {o}"
        elif p == "leader":
            fragment = f"The leader of {s} is {o}"
        elif p == "leaderTitle":
            fragment = f"The leader title of {s} is {o}"
        elif p == "alternativeName":
            fragment = f"{s}, also known as {o}"
        elif p == "ethnicGroup":
            fragment = f"{s} is of {o} descent"
        elif p == "demonym":
            fragment = f"{s} people are known as {o}"
        elif p == "currency":
            fragment = f"The currency of {s} is {o}"
        elif p == "anthem":
            fragment = f"The anthem of {s} is {o}"
        elif p == "isPartOf":
            fragment = f"{s} is part of {o}"
        elif p == "distributingCompany":
            fragment = f"{s} is distributed by {o}"
        elif p == "training":
            fragment = f"{s} was trained at {o}"
        elif p == "professionalField":
            fragment = f"{s} works in {o}"
        elif p == "foundingDate":
            fragment = f"{s} was founded on {o}"
        elif p == "location":
            fragment = f"{s} is located in {o}"
        elif p == "background":
            fragment = f"{s} is a {o}"
        elif p == "musicFusionGenre":
            fragment = f"{s} is a fusion of {o}"
        elif p == "musicSubgenre":
            fragment = f"{s} is a subgenre of {o}"
        elif p == "stylisticOrigin":
            fragment = f"{s} has origins in {o}"
        elif p == "derivative":
            fragment = f"{s} influenced {o}"
        elif p == "meaning":
            fragment = f"{s} means {o}"
        elif p == "longName":
            fragment = f"{s}, officially {o}"
        elif p == "areaTotal":
            fragment = f"The total area of {s} is {o}"
        elif p == "elevationAboveTheSeaLevel":
            fragment = f"{s} has an elevation of {o} meters above sea level"
        elif p == "postalCode":
            fragment = f"The postal code for {s} is {o}"
        elif p == "populationDensity":
            fragment = f"{s} has a population density of {o}"
        elif p == "governingBody":
            fragment = f"{s} is governed by {o}"
        else:
            # Fallback generic rendering
            fragment = f"{s} {p} {o}"

        fragments.append(fragment.rstrip("."))

    # Join phrases into a coherent sentence
    if len(fragments) == 1:
        return fragments[0] + "."
    else:
        # Create more complex, natural sentences by grouping related facts
        result_parts = []
        for i, frag in enumerate(fragments):
            if i == len(fragments) - 1:
                result_parts.append("and " + frag)
            elif i == len(fragments) - 2:
                result_parts.append(frag)
            else:
                result_parts.append(frag + ",")

        return " ".join(result_parts) + "."

